import { SeparatorHorizontal, Text } from '@semparar/design-system-app';
import { UINodes } from '../../../services/models/ui.model';

export function KeyValueRow(props: {
  config: UINodes['KeyValueRow']['props'];
}) {
  const {
    label,
    value,
    showDivider = true,
    labelType = 'paragraphXL',
    labelColor = 'BRAND_COMPLEMENT_01',
    valueType = 'paragraphMD',
    valueColor = 'INTENSE_COLOR_03',
  } = props;

  return (
    <>
      {showDivider && (
        <SeparatorHorizontal
          borderWidth="smaller"
          borderColor="BRAND_COMPLEMENT_02"
          height={1}
          width="100%"
          mt="xxxxs"
        />
      )}
      <Text type={labelType} color={labelColor} mb="xxxxs" mt="xxxxs">
        {label}
      </Text>
      <Text type={valueType} color={valueColor}>
        {value}
      </Text>
    </>
  );
}

